try {
  const b = $input.first().json.body || $input.first().json;
  if (!b.url) throw new Error('URL is required.');
  return [{ json: { url: b.url, extractFields: b.extract_fields || 'price,features,description', name: b.name || '' } }];
} catch (e) { throw new Error('Invalid input: ' + e.message); }

try {
  const url = $('Validate').first().json;
  const r = $input.first().json;
  const html = typeof r === 'string' ? r : (r.data || r.body || JSON.stringify(r));
  const text = html.replace(/<script[^>]*>[\s\S]*?<\/script>/gi,'').replace(/<style[^>]*>[\s\S]*?<\/style>/gi,'').replace(/<[^>]+>/g,' ').replace(/\s+/g,' ').trim().substring(0,4000);
  return [{ json: { ...url, pageText: text } }];
} catch(e) { throw new Error('Extract failed: ' + e.message); }
